SELECT bi.frame, bi.time, bi.number, bu.nucleus, bu.total, bf.money, COALESCE(bf.money,0) as money, bi.people, bi.user, bi.data FROM bill bi INNER JOIN buy bu ON bi.number=bu.number INNER JOIN imy_bill bf ON bi.id=bf.pid
AND #{query.type2}=0
bi.number LIKE CONCAT('%', #{query.number}, '%')
AND bu.nucleus = #{query.nucleus}
AND bi.time >= #{query.startTime}
AND bi.time <= #{query.endTime}
AND bi.user LIKE CONCAT('%', #{query.user}, '%')
AND bi.data LIKE CONCAT('%', #{query.data}, '%')
ORDER BY bi.time DESC

