SELECT b.frame, b.customer, b.supplier, b.time, b.number, bi.bill, bi.money, b.people, b.examine, b.user, b.data FROM bill b INNER JOIN bill_info bi on b.id=bi.pid
AND b.customer LIKE CONCAT('%', #{query.customer}, '%')
AND b.supplier LIKE CONCAT('%', #{query.supplier}, '%')
AND b.number LIKE CONCAT('%', #{query.number}, '%')
AND b.type=#{query.type}
AND b.time >= #{query.startTime}
AND b.time <= #{query.endTime}
AND b.user LIKE CONCAT('%', #{query.user}, '%')
AND b.people LIKE CONCAT('%', #{query.people}, '%')
AND b.examine=#{query.examine}
AND b.data LIKE CONCAT('%', #{query.data}, '%')
ORDER BY b.time DESC
